class Solution:
    def longestDiverseString(self, a, b, c):
        """
        :type a: int
        :type b: int
        :type c: int
        :rtype: str
        """
        import heapq

        # Max heap (negate counts)
        heap = []
        if a > 0:
            heapq.heappush(heap, (-a, 'a'))
        if b > 0:
            heapq.heappush(heap, (-b, 'b'))
        if c > 0:
            heapq.heappush(heap, (-c, 'c'))

        result = []

        while heap:
            # Get most frequent character
            first_count, first_char = heapq.heappop(heap)

            if len(result) >= 2 and result[-1] == result[-2] == first_char:
                # Can't use this character, need second most frequent
                if not heap:
                    break

                second_count, second_char = heapq.heappop(heap)
                result.append(second_char)

                # Push back if still has count
                if second_count < -1:
                    heapq.heappush(heap, (second_count + 1, second_char))
                heapq.heappush(heap, (first_count, first_char))
            else:
                # Use first character
                result.append(first_char)
                if first_count < -1:
                    heapq.heappush(heap, (first_count + 1, first_char))

        return ''.join(result)
